1	/* ================================================================
2	   glass.css — ToolBox 液态玻璃主题
3	   适用于 JavaFX 8+ (CSS 2.1 子集 + JavaFX 扩展属性)
4	   ================================================================ */
5	
6	/* ── 根变量（JavaFX 不支持 var()，改用 looked-up color） ───────
7	   在 Scene 根节点定义，子节点通过名称引用                        */
8	.root {
9	    -fx-font-family: "SF Pro Display", "PingFang SC", "Microsoft YaHei", sans-serif;
10	    -fx-font-size: 13px;
11	
12	    /* 基础色板 */
13	    -glass-bg:          rgba(255,255,255,0.055);
14	    -glass-bg-hover:    rgba(255,255,255,0.09);
15	    -glass-border:      rgba(255,255,255,0.10);
16	    -glass-border-hi:   rgba(255,255,255,0.22);
17	
18	    -accent:            #5b8cf7;
19	    -accent-soft:       rgba(91,140,247,0.18);
20	    -accent-glow:       rgba(91,140,247,0.35);
21	
22	    -text-primary:      rgba(255,255,255,0.92);
23	    -text-secondary:    rgba(255,255,255,0.50);
24	    -text-tertiary:     rgba(255,255,255,0.28);
25	
26	    -success:           #4cd97b;
27	    -warning:           #f5a623;
28	    -danger:            #f25c5c;
29	
30	    /* 组件尺寸 */
31	    -sidebar-width:     220px;
32	    -titlebar-height:   44px;
33	    -card-radius:       12px;
34	    -nav-radius:        8px;
35	}
36	
37	/* ── 窗口根 ──────────────────────────────────────────────────── */
38	.app-root {
39	    -fx-background-color: transparent;
40	}
41	
42	/* ── 标题栏 ──────────────────────────────────────────────────── */
43	.titlebar {
44	    -fx-background-color: rgba(255,255,255,0.025);
45	    -fx-border-color: rgba(255,255,255,0.10);
46	    -fx-border-width: 0 0 1 0;
47	    -fx-pref-height: 44px;
48	    -fx-min-height: 44px;
49	    -fx-padding: 0 16 0 16;
50	}
51	
52	/* macOS 红绿灯 */
53	.traffic-light {
54	    -fx-pref-width: 12px;
55	    -fx-pref-height: 12px;
56	    -fx-min-width: 12px;
57	    -fx-min-height: 12px;
58	    -fx-background-radius: 6px;
59	    -fx-border-radius: 6px;
60	    -fx-border-width: 0.5px;
61	    -fx-border-color: rgba(0,0,0,0.20);
62	    -fx-cursor: hand;
63	    -fx-effect: innershadow(gaussian, rgba(255,255,255,0.35), 1, 0, 0, 0.5);
64	}
65	.traffic-light-close {
66	    -fx-background-color: linear-gradient(to bottom, #ff6259 0%, #ee4f44 100%);
67	}
68	.traffic-light-min {
69	    -fx-background-color: linear-gradient(to bottom, #ffbe2f 0%, #efaa18 100%);
70	}
71	.traffic-light-max {
72	    -fx-background-color: linear-gradient(to bottom, #2bc940 0%, #1eaf2f 100%);
73	}
74	.traffic-light:hover {
75	    -fx-effect: innershadow(gaussian, rgba(255,255,255,0.45), 1, 0, 0, 0.5),
76	                dropshadow(gaussian, rgba(0,0,0,0.15), 2, 0, 0, 0.5);
77	}
78	.traffic-light:pressed {
79	    -fx-opacity: 0.78;
80	}
81	
82	.titlebar-title {
83	    -fx-text-fill: rgba(255,255,255,0.50);
84	    -fx-font-size: 13px;
85	    -fx-font-weight: 500;
86	}
87	
88	/* ── 侧边栏 ──────────────────────────────────────────────────── */
89	.sidebar {
90	    -fx-background-color: rgba(255,255,255,0.022);
91	    -fx-border-color: rgba(255,255,255,0.10);
92	    -fx-border-width: 0 1 0 0;
93	    -fx-pref-width: 220px;
94	    -fx-min-width: 200px;
95	    -fx-max-width: 260px;
96	    -fx-padding: 12 8 12 8;
97	    -fx-spacing: 2px;
98	}
99	
100	.sidebar-section-label {
101	    -fx-text-fill: rgba(255,255,255,1);
102	    -fx-font-size: 10px;
103	    -fx-font-weight: bold;
104	    -fx-padding: 10 10 4 10;
105	}
106	
107	.nav-item {
108	    -fx-background-color: transparent;
109	    -fx-background-radius: 8px;
110	    -fx-border-color: transparent;
111	    -fx-border-radius: 8px;
112	    -fx-border-width: 1px;
113	    -fx-padding: 8 10 8 10;
114	    -fx-cursor: hand;
115	    -fx-alignment: center-left;
116	    -fx-spacing: 10px;
117	    -fx-pref-height: 34px;
118	}
119	.nav-item-icon {
120	    -fx-font-size: 14px;
121	    -fx-min-width: 18px;
122	    -fx-alignment: center;
123	    -fx-text-fill: rgba(255,255,255,0.75);
124	}
125	.nav-item-text {
126	    -fx-font-size: 13px;
127	    -fx-text-fill: rgba(255,255,255,0.75);
128	}
129	.nav-item:hover .nav-item-icon,
130	.nav-item:hover .nav-item-text {
131	    -fx-text-fill: rgba(255,255,255,1);
132	}
133	.nav-item:hover {
134	    -fx-background-color: rgba(255,255,255,0.055);
135	    -fx-border-color: rgba(255,255,255,0.10);
136	}
137	.nav-item.active {
138	    -fx-background-color: rgba(91,140,247,0.18);
139	    -fx-border-color: rgba(91,140,247,0.25);
140	    -fx-font-weight: 500;
141	}
142	.nav-item.active .nav-item-icon,
143	.nav-item.active .nav-item-text {
144	    -fx-text-fill: #5b8cf7;
145	}
146	
147	.nav-badge {
148	    -fx-background-color: rgba(91,140,247,0.18);
149	    -fx-text-fill: #5b8cf7;
150	    -fx-background-radius: 20px;
151	    -fx-padding: 1 7 1 7;
152	    -fx-font-size: 10px;
153	    -fx-font-weight: bold;
154	}
155	.nav-badge-new {
156	    -fx-background-color: rgba(76,217,123,0.18);
157	    -fx-text-fill: #4cd97b;
158	}
159	
160	.sidebar-divider {
161	    -fx-border-color: rgba(255,255,255,0.10);
162	    -fx-border-width: 1 0 0 0;
163	    -fx-pref-height: 1px;
164	    -fx-padding: 4 4 4 4;
165	}
166	
167	/* ── 搜索栏 ──────────────────────────────────────────────────── */
168	.search-bar {
169	    -fx-background-color: rgba(255,255,255,0.055);
170	    -fx-border-color: rgba(255,255,255,0.10);
171	    -fx-border-width: 1px;
172	    -fx-border-radius: 10px;
173	    -fx-background-radius: 10px;
174	    -fx-padding: 0 14 0 14;
175	    -fx-pref-height: 38px;
176	    -fx-spacing: 10px;
177	}
178	.search-bar:focused-within {
179	    -fx-background-color: rgba(255,255,255,0.085);
180	    -fx-border-color: rgba(255,255,255,0.22);
181	    -fx-effect: dropshadow(gaussian, rgba(91,140,247,0.35), 10, 0, 0, 0);
182	}
183	.search-field {
184	    -fx-background-color: transparent;
185	    -fx-border-width: 0;
186	    -fx-text-fill: rgba(255,255,255,0.92);
187	    -fx-prompt-text-fill: rgba(255,255,255,0.28);
188	    -fx-font-size: 13.5px;
189	}
190	.search-field:focused { -fx-background-color: transparent; }
191	
192	/* ── 工具卡片 ─────────────────────────────────────────────────── */
193	.tool-card {
194	    -fx-background-color: rgba(255,255,255,0.055);
195	    -fx-border-color: rgba(255,255,255,0.10);
196	    -fx-border-width: 1px;
197	    -fx-border-radius: 12px;
198	    -fx-background-radius: 12px;
199	    -fx-padding: 16 14 14 14;
200	    -fx-cursor: hand;
201	    -fx-pref-width: 152px;
202	    -fx-pref-height: 130px;
203	    -fx-spacing: 3px;
204	}
205	.tool-card:hover {
206	    -fx-background-color: rgba(255,255,255,0.085);
207	    -fx-border-color: rgba(255,255,255,0.22);
208	    -fx-effect: dropshadow(gaussian, rgba(0,0,0,0.35), 18, 0, 0, 6);
209	    -fx-translate-y: -2px;
210	}
211	
212	.tool-icon-wrap {
213	    -fx-pref-width: 48px;
214	    -fx-pref-height: 48px;
215	    -fx-min-width: 48px;
216	    -fx-min-height: 48px;
217	    -fx-background-color: transparent;
218	    -fx-border-color: transparent;
219	    -fx-border-width: 0;
220	    -fx-alignment: center;
221	}
222	
223	/* 图标配色 — 颜色注入到 Text 节点上，glow 由 Java 代码通过 DropShadow 设置 */
224	.ic-blue   { }
225	.ic-purple { }
226	.ic-teal   { }
227	.ic-amber  { }
228	.ic-red    { }
229	.ic-pink   { }
230	.ic-gray   { }
231	
232	.tool-name {
233	    -fx-text-fill: rgba(255,255,255,0.92);
234	    -fx-font-size: 13px;
235	    -fx-font-weight: 500;
236	}
237	.tool-desc {
238	    -fx-text-fill: rgba(255,255,255,0.38);
239	    -fx-font-size: 11px;
240	    -fx-wrap-text: true;
241	}
242	.tool-tag {
243	    -fx-background-color: rgba(255,255,255,0.06);
244	    -fx-text-fill: rgba(255,255,255,0.38);
245	    -fx-border-color: rgba(255,255,255,0.10);
246	    -fx-border-width: 1px;
247	    -fx-background-radius: 4px;
248	    -fx-border-radius: 4px;
249	    -fx-padding: 1 6 1 6;
250	    -fx-font-size: 10px;
251	}
252	.tool-tag-plugin {
253	    -fx-background-color: rgba(76,217,123,0.12);
254	    -fx-text-fill: #4cd97b;
255	    -fx-border-color: rgba(76,217,123,0.20);
256	}
257	
258	/* ── 详情面板 ─────────────────────────────────────────────────── */
259	.detail-panel {
260	    -fx-background-color: rgba(255,255,255,0.022);
261	    -fx-border-color: rgba(255,255,255,0.10);
262	    -fx-border-width: 0 0 0 1;
263	    -fx-padding: 20 16 20 16;
264	    -fx-spacing: 10px;
265	    -fx-pref-width: 260px;
266	}
267	
268	.detail-launch-btn {
269	    -fx-background-color: #5b8cf7;
270	    -fx-text-fill: white;
271	    -fx-font-weight: 500;
272	    -fx-background-radius: 8px;
273	    -fx-border-radius: 8px;
274	    -fx-border-width: 0;
275	    -fx-pref-height: 36px;
276	    -fx-cursor: hand;
277	}
278	.detail-launch-btn:hover {
279	    -fx-background-color: #4a7bf5;
280	    -fx-effect: dropshadow(gaussian, rgba(91,140,247,0.4), 12, 0, 0, 3);
281	    -fx-translate-y: -1px;
282	}
283	.detail-launch-btn:pressed {
284	    -fx-translate-y: 0;
285	    -fx-effect: none;
286	}
287	
288	/* ── 状态栏 ──────────────────────────────────────────────────── */
289	.statusbar {
290	    -fx-background-color: rgba(255,255,255,0.015);
291	    -fx-border-color: rgba(255,255,255,0.10);
292	    -fx-border-width: 1 0 0 0;
293	    -fx-pref-height: 28px;
294	    -fx-min-height: 28px;
295	    -fx-padding: 0 16 0 16;
296	    -fx-spacing: 12px;
297	}
298	.status-text {
299	    -fx-text-fill: rgba(255,255,255,0.28);
300	    -fx-font-size: 11px;
301	    -fx-font-family: "SF Mono", "Consolas", monospace;
302	}
303	
304	/* ── 内容区滚动面板（首页 / 工具页主滚动条，纤细 4px） ─────────── */
305	.content-scroll .scroll-bar:vertical { -fx-pref-width: 4px; }
306	.content-scroll .scroll-bar:horizontal { -fx-pref-height: 4px; }
307	.content-scroll .scroll-bar .thumb {
308	    -fx-background-color: rgba(255,255,255,0.12);
309	    -fx-background-radius: 4px;
310	}
311	.content-scroll .scroll-bar .thumb:hover,
312	.content-scroll .scroll-bar .thumb:pressed {
313	    -fx-background-color: rgba(255,255,255,0.22);
314	}
315	.content-scroll .scroll-bar .track,
316	.content-scroll .scroll-bar .track-background,
317	.content-scroll .increment-button,
318	.content-scroll .decrement-button {
319	    -fx-background-color: transparent;
320	    -fx-border-color: transparent;
321	}
322	.content-scroll .increment-arrow,
323	.content-scroll .decrement-arrow {
324	    -fx-shape: " ";
325	    -fx-padding: 0;
326	}
327	
328	/* ── 全局滚动条（插件内部的 ScrollPane / TableView / TextArea / WebView / ComboBox 下拉等） ─── */
329	.scroll-bar:vertical { -fx-pref-width: 8px; }
330	.scroll-bar:horizontal { -fx-pref-height: 8px; }
331	.scroll-bar {
332	    -fx-background-color: transparent;
333	}
334	.scroll-bar .track,
335	.scroll-bar .track-background {
336	    -fx-background-color: transparent;
337	    -fx-border-color: transparent;
338	}
339	.scroll-bar .thumb {
340	    -fx-background-color: rgba(255,255,255,0.14);
341	    -fx-background-radius: 6px;
342	    -fx-border-color: transparent;
343	}
344	.scroll-bar .thumb:hover,
345	.scroll-bar .thumb:pressed {
346	    -fx-background-color: rgba(255,255,255,0.26);
347	}
348	.scroll-bar .increment-button,
349	.scroll-bar .decrement-button {
350	    -fx-background-color: transparent;
351	    -fx-border-color: transparent;
352	    -fx-padding: 0;
353	}
354	.scroll-bar .increment-arrow,
355	.scroll-bar .decrement-arrow {
356	    -fx-shape: " ";
357	    -fx-padding: 0;
358	}
359	/* ScrollPane / TableView 视口背景，避免插件嵌入后出现浅灰色边角 */
360	.scroll-pane,
361	.scroll-pane > .viewport,
362	.scroll-pane .corner {
363	    -fx-background-color: transparent;
364	}
365	
366	/* ── 全局进度条（与首页 accent 主题色一致，纤细 6px） ────────── */
367	.progress-bar {
368	    -fx-pref-height: 6px;
369	}
370	.progress-bar > .track {
371	    -fx-background-color: rgba(255,255,255,0.08);
372	    -fx-background-radius: 3px;
373	    -fx-border-color: transparent;
374	}
375	.progress-bar > .bar {
376	    -fx-background-color: #5b8cf7;
377	    -fx-background-radius: 3px;
378	    -fx-background-insets: 0;
379	    -fx-padding: 0;
380	}
381	.progress-bar:indeterminate > .bar {
382	    -fx-background-color: linear-gradient(to right,
383	        rgba(91,140,247,0.0) 0%,
384	        rgba(91,140,247,1.0) 50%,
385	        rgba(91,140,247,0.0) 100%);
386	}
387	/* 成功 / 失败 状态：在 ProgressBar 上加 style class 即可 */
388	.progress-bar.success > .bar { -fx-background-color: #4cd97b; }
389	.progress-bar.danger  > .bar { -fx-background-color: #f25c5c; }
390	
391	/* ── 区块标题 ─────────────────────────────────────────────────── */
392	.section-title {
393	    -fx-text-fill: rgba(255,255,255,0.28);
394	    -fx-font-size: 11px;
395	    -fx-font-weight: bold;
396	}
397

