/* ================================================================
   glass.css — ToolBox 液态玻璃主题
   适用于 JavaFX 8+ (CSS 2.1 子集 + JavaFX 扩展属性)
   ================================================================ */

/* ── 根变量（JavaFX 不支持 var()，改用 looked-up color） ───────
   在 Scene 根节点定义，子节点通过名称引用                        */
.root {
    -fx-font-family: "SF Pro Display", "PingFang SC", "Microsoft YaHei", sans-serif;
    -fx-font-size: 13px;

    /* 基础色板 */
    -glass-bg:          rgba(255,255,255,0.055);
    -glass-bg-hover:    rgba(255,255,255,0.09);
    -glass-border:      rgba(255,255,255,0.10);
    -glass-border-hi:   rgba(255,255,255,0.22);

    -accent:            #5b8cf7;
    -accent-soft:       rgba(91,140,247,0.18);
    -accent-glow:       rgba(91,140,247,0.35);

    -text-primary:      rgba(255,255,255,0.92);
    -text-secondary:    rgba(255,255,255,0.50);
    -text-tertiary:     rgba(255,255,255,0.28);

    -success:           #4cd97b;
    -warning:           #f5a623;
    -danger:            #f25c5c;

    /* 组件尺寸 */
    -sidebar-width:     220px;
    -titlebar-height:   44px;
    -card-radius:       12px;
    -nav-radius:        8px;
}

/* ── 窗口根 ──────────────────────────────────────────────────── */
.app-root {
    -fx-background-color: transparent;
}

/* ── 标题栏 ──────────────────────────────────────────────────── */
.titlebar {
    -fx-background-color: rgba(255,255,255,0.025);
    -fx-border-color: rgba(255,255,255,0.10);
    -fx-border-width: 0 0 1 0;
    -fx-pref-height: 44px;
    -fx-min-height: 44px;
    -fx-padding: 0 16 0 16;
}

/* macOS 红绿灯 */
.traffic-light {
    -fx-pref-width: 12px;
    -fx-pref-height: 12px;
    -fx-min-width: 12px;
    -fx-min-height: 12px;
    -fx-background-radius: 6px;
    -fx-border-radius: 6px;
    -fx-border-width: 0.5px;
    -fx-border-color: rgba(0,0,0,0.20);
    -fx-cursor: hand;
    -fx-effect: innershadow(gaussian, rgba(255,255,255,0.35), 1, 0, 0, 0.5);
}
.traffic-light-close {
    -fx-background-color: linear-gradient(to bottom, #ff6259 0%, #ee4f44 100%);
}
.traffic-light-min {
    -fx-background-color: linear-gradient(to bottom, #ffbe2f 0%, #efaa18 100%);
}
.traffic-light-max {
    -fx-background-color: linear-gradient(to bottom, #2bc940 0%, #1eaf2f 100%);
}
.traffic-light:hover {
    -fx-effect: innershadow(gaussian, rgba(255,255,255,0.45), 1, 0, 0, 0.5),
                dropshadow(gaussian, rgba(0,0,0,0.15), 2, 0, 0, 0.5);
}
.traffic-light:pressed {
    -fx-opacity: 0.78;
}

.titlebar-title {
    -fx-text-fill: rgba(255,255,255,0.50);
    -fx-font-size: 13px;
    -fx-font-weight: 500;
}

/* ── 侧边栏 ──────────────────────────────────────────────────── */
.sidebar {
    -fx-background-color: rgba(255,255,255,0.022);
    -fx-border-color: rgba(255,255,255,0.10);
    -fx-border-width: 0 1 0 0;
    -fx-pref-width: 220px;
    -fx-min-width: 200px;
    -fx-max-width: 260px;
    -fx-padding: 12 8 12 8;
    -fx-spacing: 2px;
}

.sidebar-section-label {
    -fx-text-fill: rgba(255,255,255,1);
    -fx-font-size: 10px;
    -fx-font-weight: bold;
    -fx-padding: 10 10 4 10;
}

.nav-item {
    -fx-background-color: transparent;
    -fx-background-radius: 8px;
    -fx-border-color: transparent;
    -fx-border-radius: 8px;
    -fx-border-width: 1px;
    -fx-padding: 8 10 8 10;
    -fx-cursor: hand;
    -fx-alignment: center-left;
    -fx-spacing: 10px;
    -fx-pref-height: 34px;
}
.nav-item-icon {
    -fx-font-size: 14px;
    -fx-min-width: 18px;
    -fx-alignment: center;
    -fx-text-fill: rgba(255,255,255,0.75);
}
.nav-item-text {
    -fx-font-size: 13px;
    -fx-text-fill: rgba(255,255,255,0.75);
}
.nav-item:hover .nav-item-icon,
.nav-item:hover .nav-item-text {
    -fx-text-fill: rgba(255,255,255,1);
}
.nav-item:hover {
    -fx-background-color: rgba(255,255,255,0.055);
    -fx-border-color: rgba(255,255,255,0.10);
}
.nav-item.active {
    -fx-background-color: rgba(91,140,247,0.18);
    -fx-border-color: rgba(91,140,247,0.25);
    -fx-font-weight: 500;
}
.nav-item.active .nav-item-icon,
.nav-item.active .nav-item-text {
    -fx-text-fill: #5b8cf7;
}

.nav-badge {
    -fx-background-color: rgba(91,140,247,0.18);
    -fx-text-fill: #5b8cf7;
    -fx-background-radius: 20px;
    -fx-padding: 1 7 1 7;
    -fx-font-size: 10px;
    -fx-font-weight: bold;
}
.nav-badge-new {
    -fx-background-color: rgba(76,217,123,0.18);
    -fx-text-fill: #4cd97b;
}

.sidebar-divider {
    -fx-border-color: rgba(255,255,255,0.10);
    -fx-border-width: 1 0 0 0;
    -fx-pref-height: 1px;
    -fx-padding: 4 4 4 4;
}

/* ── 搜索栏 ──────────────────────────────────────────────────── */
.search-bar {
    -fx-background-color: rgba(255,255,255,0.055);
    -fx-border-color: rgba(255,255,255,0.10);
    -fx-border-width: 1px;
    -fx-border-radius: 10px;
    -fx-background-radius: 10px;
    -fx-padding: 0 14 0 14;
    -fx-pref-height: 38px;
    -fx-spacing: 10px;
}
.search-bar:focused-within {
    -fx-background-color: rgba(255,255,255,0.085);
    -fx-border-color: rgba(255,255,255,0.22);
    -fx-effect: dropshadow(gaussian, rgba(91,140,247,0.35), 10, 0, 0, 0);
}
.search-field {
    -fx-background-color: transparent;
    -fx-border-width: 0;
    -fx-text-fill: rgba(255,255,255,0.92);
    -fx-prompt-text-fill: rgba(255,255,255,0.28);
    -fx-font-size: 13.5px;
}
.search-field:focused { -fx-background-color: transparent; }

/* ── 工具卡片 ─────────────────────────────────────────────────── */
.tool-card {
    -fx-background-color: rgba(255,255,255,0.055);
    -fx-border-color: rgba(255,255,255,0.10);
    -fx-border-width: 1px;
    -fx-border-radius: 12px;
    -fx-background-radius: 12px;
    -fx-padding: 16 14 14 14;
    -fx-cursor: hand;
    -fx-pref-width: 152px;
    -fx-pref-height: 130px;
    -fx-spacing: 3px;
}
.tool-card:hover {
    -fx-background-color: rgba(255,255,255,0.085);
    -fx-border-color: rgba(255,255,255,0.22);
    -fx-effect: dropshadow(gaussian, rgba(0,0,0,0.35), 18, 0, 0, 6);
    -fx-translate-y: -2px;
}

.tool-icon-wrap {
    -fx-pref-width: 48px;
    -fx-pref-height: 48px;
    -fx-min-width: 48px;
    -fx-min-height: 48px;
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-alignment: center;
}

/* 图标配色 — 颜色注入到 Text 节点上，glow 由 Java 代码通过 DropShadow 设置 */
.ic-blue   { }
.ic-purple { }
.ic-teal   { }
.ic-amber  { }
.ic-red    { }
.ic-pink   { }
.ic-gray   { }

.tool-name {
    -fx-text-fill: rgba(255,255,255,0.92);
    -fx-font-size: 13px;
    -fx-font-weight: 500;
}
.tool-desc {
    -fx-text-fill: rgba(255,255,255,0.38);
    -fx-font-size: 11px;
    -fx-wrap-text: true;
}
.tool-tag {
    -fx-background-color: rgba(255,255,255,0.06);
    -fx-text-fill: rgba(255,255,255,0.38);
    -fx-border-color: rgba(255,255,255,0.10);
    -fx-border-width: 1px;
    -fx-background-radius: 4px;
    -fx-border-radius: 4px;
    -fx-padding: 1 6 1 6;
    -fx-font-size: 10px;
}
.tool-tag-plugin {
    -fx-background-color: rgba(76,217,123,0.12);
    -fx-text-fill: #4cd97b;
    -fx-border-color: rgba(76,217,123,0.20);
}

/* ── 详情面板 ─────────────────────────────────────────────────── */
.detail-panel {
    -fx-background-color: rgba(255,255,255,0.022);
    -fx-border-color: rgba(255,255,255,0.10);
    -fx-border-width: 0 0 0 1;
    -fx-padding: 20 16 20 16;
    -fx-spacing: 10px;
    -fx-pref-width: 260px;
}

.detail-launch-btn {
    -fx-background-color: #5b8cf7;
    -fx-text-fill: white;
    -fx-font-weight: 500;
    -fx-background-radius: 8px;
    -fx-border-radius: 8px;
    -fx-border-width: 0;
    -fx-pref-height: 36px;
    -fx-cursor: hand;
}
.detail-launch-btn:hover {
    -fx-background-color: #4a7bf5;
    -fx-effect: dropshadow(gaussian, rgba(91,140,247,0.4), 12, 0, 0, 3);
    -fx-translate-y: -1px;
}
.detail-launch-btn:pressed {
    -fx-translate-y: 0;
    -fx-effect: none;
}

/* ── 状态栏 ──────────────────────────────────────────────────── */
.statusbar {
    -fx-background-color: rgba(255,255,255,0.015);
    -fx-border-color: rgba(255,255,255,0.10);
    -fx-border-width: 1 0 0 0;
    -fx-pref-height: 28px;
    -fx-min-height: 28px;
    -fx-padding: 0 16 0 16;
    -fx-spacing: 12px;
}
.status-text {
    -fx-text-fill: rgba(255,255,255,0.28);
    -fx-font-size: 11px;
    -fx-font-family: "SF Mono", "Consolas", monospace;
}

/* ── 内容区滚动面板（首页 / 工具页主滚动条，纤细 4px） ─────────── */
.content-scroll .scroll-bar:vertical { -fx-pref-width: 4px; }
.content-scroll .scroll-bar:horizontal { -fx-pref-height: 4px; }
.content-scroll .scroll-bar .thumb {
    -fx-background-color: rgba(255,255,255,0.12);
    -fx-background-radius: 4px;
}
.content-scroll .scroll-bar .thumb:hover,
.content-scroll .scroll-bar .thumb:pressed {
    -fx-background-color: rgba(255,255,255,0.22);
}
.content-scroll .scroll-bar .track,
.content-scroll .scroll-bar .track-background,
.content-scroll .increment-button,
.content-scroll .decrement-button {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
}
.content-scroll .increment-arrow,
.content-scroll .decrement-arrow {
    -fx-shape: " ";
    -fx-padding: 0;
}

/* ── 全局滚动条（插件内部的 ScrollPane / TableView / TextArea / WebView / ComboBox 下拉等） ─── */
.scroll-bar:vertical { -fx-pref-width: 8px; }
.scroll-bar:horizontal { -fx-pref-height: 8px; }
.scroll-bar {
    -fx-background-color: transparent;
}
.scroll-bar .track,
.scroll-bar .track-background {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
}
.scroll-bar .thumb {
    -fx-background-color: rgba(255,255,255,0.14);
    -fx-background-radius: 6px;
    -fx-border-color: transparent;
}
.scroll-bar .thumb:hover,
.scroll-bar .thumb:pressed {
    -fx-background-color: rgba(255,255,255,0.26);
}
.scroll-bar .increment-button,
.scroll-bar .decrement-button {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-padding: 0;
}
.scroll-bar .increment-arrow,
.scroll-bar .decrement-arrow {
    -fx-shape: " ";
    -fx-padding: 0;
}
/* ScrollPane / TableView 视口背景，避免插件嵌入后出现浅灰色边角 */
.scroll-pane,
.scroll-pane > .viewport,
.scroll-pane .corner {
    -fx-background-color: transparent;
}

/* ── 全局进度条（与首页 accent 主题色一致，纤细 6px） ────────── */
.progress-bar {
    -fx-pref-height: 6px;
}
.progress-bar > .track {
    -fx-background-color: rgba(255,255,255,0.08);
    -fx-background-radius: 3px;
    -fx-border-color: transparent;
}
.progress-bar > .bar {
    -fx-background-color: #5b8cf7;
    -fx-background-radius: 3px;
    -fx-background-insets: 0;
    -fx-padding: 0;
}
.progress-bar:indeterminate > .bar {
    -fx-background-color: linear-gradient(to right,
        rgba(91,140,247,0.0) 0%,
        rgba(91,140,247,1.0) 50%,
        rgba(91,140,247,0.0) 100%);
}
/* 成功 / 失败 状态：在 ProgressBar 上加 style class 即可 */
.progress-bar.success > .bar { -fx-background-color: #4cd97b; }
.progress-bar.danger  > .bar { -fx-background-color: #f25c5c; }

/* ── 区块标题 ─────────────────────────────────────────────────── */
.section-title {
    -fx-text-fill: rgba(255,255,255,0.28);
    -fx-font-size: 11px;
    -fx-font-weight: bold;
}

