55	/**
56	 * Settings UI for SwissKit.
57	 * Displays three tabs: General (language), Email (SMTP config + address book), Plugin (JAR management).
58	 * Styled with glassmorphism consistent with the main application.
59	 */
60	public class SwissKitJSettingUi {
61	
62	    private static final Logger log = LoggerFactory.getLogger(SwissKitJSettingUi.class);
63	
64	    private static final Pattern NUMERIC_ID_PATTERN = Pattern.compile("\\d+");
65	
66	    // Static fields needed by inner methods
67	    private static TextField pluginPathField;
68	    private static TableView<PluginJarInfo> pluginTable;
69	
70	    public static Node build() {
71	        VBox container = new VBox();
72	        container.setStyle(
73	            "-fx-background-color: rgba(255,255,255,0.022);" +
74	            "-fx-border-color: rgba(255,255,255,0.10);" +
75	            "-fx-border-width: 1;" +
76	            "-fx-border-radius: 12px;" +
77	            "-fx-background-radius: 12px;" +
78	            "-fx-padding: 0;"
79	        );
80	
81	        TabPane tabs = new TabPane();
82	        tabs.setStyle("-fx-background-color: transparent;");
83	
84	        Tab generalTab = new Tab("General");
85	        generalTab.setContent(buildGeneralTab());
86	        generalTab.setStyle("-fx-background-color: transparent; -fx-padding: 10 24 10 24;");
87	
88	        Tab emailTab = new Tab("Email");
89	        emailTab.setContent(buildEmailTab());
90	        emailTab.setStyle("-fx-background-color: transparent; -fx-padding: 10 24 10 24;");
91	
92	        Tab pluginTab = new Tab("Plugin");
93	        pluginTab.setContent(buildPluginTab());
94	        pluginTab.setStyle("-fx-background-color: transparent; -fx-padding: 10 24 10 24;");
95	
96	        tabs.getTabs().addAll(generalTab, emailTab, pluginTab);
97	
98	        // Style tabs header with glass appearance
99	        VBox tabHeader = new VBox();
100	        tabHeader.setStyle(
101	            "-fx-background-color: rgba(255,255,255,0.025);" +
102	            "-fx-border-color: rgba(255,255,255,0.08);" +
103	            "-fx-border-width: 0 0 1 0;"
104	        );
105	        tabHeader.getChildren().add(tabs);
106	
107	        // Tab button styling
108	        for (int i = 0; i < tabs.getTabs().size(); i++) {
109	            Tab t = tabs.getTabs().get(i);
110	            int index = i;
111	            String baseStyle =
112	                "-fx-background-color: transparent;" +
113	                "-fx-border-color: transparent;" +
114	                "-fx-border-width: 0 0 2 0;" +
115	                "-fx-text-fill: rgba(255,255,255,0.50);" +
116	                "-fx-font-size: 13px;" +
117	                "-fx-font-weight: 500;" +
118	                "-fx-padding: 10 24 10 24;" +
119	                "-fx-cursor: hand;";
120	
121	            t.setStyle(baseStyle);
122	
123	            t.selectedProperty().addListener((obs, old, selected) -> {
124	                if (selected) {
125	                    t.setStyle(
126	                        "-fx-background-color: rgba(91,140,247,0.15);" +
127	                        "-fx-border-color: #5b8cf7;" +
128	                        "-fx-border-width: 0 0 2 0;" +
129	                        "-fx-text-fill: #5b8cf7;" +
130	                        "-fx-font-size: 13px;" +
131	                        "-fx-font-weight: 500;" +
132	                        "-fx-padding: 10 24 10 24;" +
133	                        "-fx-cursor: hand;"
134	                    );
135	                } else {
136	                    t.setStyle(baseStyle);
137	                }
138	            });
139	        }
140	
141	        container.getChildren().add(tabHeader);
142	
143	        return container;
144	    }
145	
146	    // ═══════════════════════════════════════════════════════════════════
147	    // General Tab
148	    // ═══════════════════════════════════════════════════════════════════
149	
150	    private static VBox buildGeneralTab() {
151	        Label title = sectionTitle("General Settings");
152	        Label langLabel = subLabel("Language");
153	
154	        ComboBox<String> langCombo = new ComboBox<>(FXCollections.observableArrayList("中文", "English"));
155	        langCombo.setValue(getCurrentLanguageLabel());
156	        langCombo.setStyle(comboStyle());
157	        langCombo.setMaxWidth(200);
158	        langCombo.setOnAction(e -> {
159	            String selected = langCombo.getValue();
160	            saveLanguageSetting(selected);
161	        });
162	
163	        HBox langRow = new HBox(12, langLabel, langCombo);
164	        langRow.setAlignment(Pos.CENTER_LEFT);
165	
166	        VBox root = new VBox(16, title, langRow);
167	        root.setPadding(new Insets(20));
168	        root.setStyle("-fx-background-color: transparent;");
169	        return root;
170	    }
171	
172	    private static String getCurrentLanguageLabel() {
173	        try (SqlSession session = DatabaseInit.getSqlSession()) {
174	            AppSettingMapper mapper = session.getMapper(AppSettingMapper.class);
175	            AppSettingEntity entity = mapper.selectByKey("language");
176	            if (entity != null && "en".equals(entity.getSettingValue())) {
177	                return "English";
178	            }
179	        } catch (Exception e) {
180	            log.debug("Could not read language setting", e);
181	        }
182	        return "中文";
183	    }
184	
185	    private static void saveLanguageSetting(String label) {
186	        new Thread(() -> {
187	            try (SqlSession session = DatabaseInit.getSqlSession()) {
188	                AppSettingMapper mapper = session.getMapper(AppSettingMapper.class);
189	                AppSettingEntity entity = mapper.selectByKey("language");
190	                if (entity != null) {
191	                    entity.setSettingValue("中文".equals(label) ? "zh" : "en");
192	                    mapper.update(entity);
193	                } else {
194	                    AppSettingEntity newEntity = new AppSettingEntity();
195	                    newEntity.setSettingKey("language");
196	                    newEntity.setSettingValue("中文".equals(label) ? "zh" : "en");
197	                    mapper.insert(newEntity);
198	                }
199	                session.commit();
200	                Platform.runLater(() -> {
201	                    Alert a = new Alert(Alert.AlertType.INFORMATION);
202	                    a.setTitle("Settings");
203	                    a.setHeaderText(null);
204	                    a.setContentText("Language changed. Restart may be required for full effect.");
205	                    a.showAndWait();
206	                });
207	            } catch (Exception e) {
208	                log.error("Failed to save language setting", e);
209	            }
210	        }).start();
211	    }
212	
213	    // ═══════════════════════════════════════════════════════════════════
214	    // Email Tab
215	    // ═══════════════════════════════════════════════════════════════════
216	
217	    private static VBox buildEmailTab() {
218	        VBox root = new VBox(14);
219	        root.setPadding(new Insets(20));
220	        root.setStyle("-fx-background-color: transparent;");
221	
222	        root.getChildren().addAll(
223	            sectionTitle("Email Server Settings"),
224	            labeled("SMTP Server", textField(null, "smtp.example.com")),
225	            labeled("Port", textField(null, "587")),
226	            labeled("Username", textField(null, "user@example.com")),
227	            labeled("Password", passwordField()),
228	            labeled("From Address", textField(null, "noreply@example.com")),
229	            tlsSslRow(),
230	            saveEmailBtn(),
231	            openAddressBookBtn()
232	        );
233	
234	        // Load existing email settings
235	        loadEmailSettings(root);
236	
237	        return root;
238	    }
239	
240	    private static void loadEmailSettings(VBox root) {
241	        new Thread(() -> {
242	            try (SqlSession session = DatabaseInit.getSqlSession()) {
243	                SwissKitSettingEmailMapper mapper = session.getMapper(SwissKitSettingEmailMapper.class);
244	                SwissKitSettingEmailEntity entity = mapper.selectLatest();
245	                if (entity != null) {
246	                    Platform.runLater(() -> {
247	                        for (Node child : root.getChildren()) {
248	                            if (child instanceof HBox hb) {
249	                                Object labelNode = hb.getChildren().get(0);
250	                                if (labelNode instanceof Label lbl) {
251	                                    String text = lbl.getText();
252	                                    if (text != null) {
253	                                        Object fieldNode = hb.getChildren().get(1);
254	                                        if ("SMTP Server".equals(text) && fieldNode instanceof TextField tf) {
255	                                            tf.setText(entity.getSmtpAddress());
256	                                        } else if ("Port".equals(text) && fieldNode instanceof TextField tf2) {
257	                                            tf2.setText(String.valueOf(entity.getSmtpPort()));
258	                                        } else if ("Username".equals(text) && fieldNode instanceof TextField tf3) {
259	                                            tf3.setText(entity.getEmail());
260	                                        } else if ("Password".equals(text) && fieldNode instanceof PasswordField pf) {
261	                                            pf.setText(entity.getPassword());
262	                                        } else if ("From Address".equals(text) && fieldNode instanceof TextField tf4) {
263	                                            tf4.setText(entity.getFromAddress());
264	                                        }
265	                                    }
266	                                }
267	                            }
268	                        }
269	                        // Update TLS/SSL checkboxes
270	                        for (Node child : root.getChildren()) {
271	                            if (child instanceof VBox vb && vb.getChildren().size() == 2) {
272	                                Node inner = vb.getChildren().get(1);
273	                                if (inner instanceof HBox hb && hb.getChildren().size() == 2) {
274	                                    Object first = hb.getChildren().get(0);
275	                                    Object second = hb.getChildren().get(1);
276	                                    if (first instanceof CheckBox tlsCb && "TLS".equals(tlsCb.getText()) && entity.getNeedTLS() != null) {
277	                                        tlsCb.setSelected(entity.getNeedTLS());
278	                                    } else if (second instanceof CheckBox sslCb && "SSL".equals(sslCb.getText()) && entity.getNeedSSL() != null) {
279	                                        sslCb.setSelected(entity.getNeedSSL());
280	                                    }
281	                                }
282	                            }
283	                        }
284	                    });
285	                }
286	            } catch (Exception e) {
287	                log.debug("No existing email settings found", e);
288	            }
289	        }).start();
290	    }
291	
292	    private static VBox tlsSslRow() {
293	        CheckBox tlsCheck = new CheckBox("TLS");
294	        tlsCheck.setStyle("-fx-text-fill: rgba(255,255,255,0.75); -fx-font-size: 13px;");
295	
296	        CheckBox sslCheck = new CheckBox("SSL");
297	        sslCheck.setStyle("-fx-text-fill: rgba(255,255,255,0.75); -fx-font-size: 13px;");
298	
299	        HBox checkRow = new HBox(16, tlsCheck, sslCheck);
300	        checkRow.setAlignment(Pos.CENTER_LEFT);
301	
302	        VBox box = new VBox(4);
303	        Label lbl = new Label("");
304	        lbl.setStyle("-fx-text-fill: rgba(255,255,255,0.50); -fx-font-size: 11px; -fx-font-weight: bold;");
305	        box.getChildren().add(lbl);
306	        box.getChildren().add(checkRow);
307	        return box;
308	    }
309	
310	    private static Button saveEmailBtn() {
311	        Button btn = glassBtn("Save", true);
312	        btn.setOnAction(e -> {
313	            VBox parent = (VBox) btn.getParent();
314	            saveEmailSettings(parent);
315	        });
316	        return btn;
317	    }
318	
319	    private static void saveEmailSettings(VBox form) {
320	        String smtp = null, port = null, user = null, pass = null, from = null;
321	        boolean tls = false, ssl = false;
322	        List<Node> children = form.getChildren();
323	
324	        for (Node child : children) {
325	            if (child instanceof HBox hb && hb.getChildren().size() >= 2) {
326	                Object first = hb.getChildren().get(0);
327	                if (first instanceof Label lbl) {
328	                    String text = lbl.getText();
329	                    Object field = hb.getChildren().get(1);
330	                    if ("SMTP Server".equals(text) && field instanceof TextField tf) smtp = tf.getText();
331	                    else if ("Port".equals(text) && field instanceof TextField tf) port = tf.getText();
332	                    else if ("Username".equals(text) && field instanceof TextField tf) user = tf.getText();
333	                    else if ("Password".equals(text) && field instanceof PasswordField pf) pass = pf.getText();
334	                    else if ("From Address".equals(text) && field instanceof TextField tf) from = tf.getText();
335	                }
336	            } else if (child instanceof VBox vb) {
337	                for (Node vbChild : vb.getChildren()) {
338	                    if (vbChild instanceof HBox hb && hb.getChildren().size() == 2) {
339	                        Object first = hb.getChildren().get(0);
340	                        Object second = hb.getChildren().get(1);
341	                        if (first instanceof CheckBox tlsCb && "TLS".equals(tlsCb.getText())) tls = tlsCb.isSelected();
342	                        if (second instanceof CheckBox sslCb && "SSL".equals(sslCb.getText())) ssl = sslCb.isSelected();
343	                    }
344	                }
345	            }
346	        }
347	
348	        if (smtp == null || smtp.isBlank() || port == null || port.isBlank()
349	                || user == null || user.isBlank() || pass == null || pass.isBlank()
350	                || from == null || from.isBlank()) {
351	            alert(Alert.AlertType.WARNING, "Validation Error", "All fields are required.");
352	            return;
353	        }
354	
355	        if (tls && ssl) {
356	            alert(Alert.AlertType.WARNING, "Validation Error", "TLS and SSL cannot be both selected.");
357	            return;
358	        }
359	
360	        final String fSmtp = smtp.trim();
361	        final String fPort = port.trim();
362	        final String fUser = user.trim();
363	        final String fPass = pass.trim();
364	        final String fFrom = from.trim();
365	        final boolean fTls = tls;
366	        final boolean fSsl = ssl;
