875	    private static void refreshPluginList() {
876	        new Thread(() -> {
877	            try {
878	                Path pluginDir = Path.of(System.getProperty("user.dir"), "plugins");
879	                List<PluginJarInfo> plugins = new ArrayList<>();
880	                if (Files.exists(pluginDir)) {
881	                    try (var stream = Files.list(pluginDir)) {
882	                        stream.filter(p -> p.getFileName().toString().toLowerCase().endsWith(".jar"))
883	                            .forEach(p -> {
884	                                try {
885	                                    long size = Files.size(p);
886	                                    String sizeStr;
887	                                    if (size < 1024) sizeStr = size + " B";
888	                                    else if (size < 1024 * 1024) sizeStr = String.format("%.1f KB", size / 1024.0);
889	                                    else sizeStr = String.format("%.1f MB", size / (1024.0 * 1024.0));
890	
891	                                    String version = "N/A";
892	                                    String status = "Enabled";
893	
894	                                    try (SqlSession session = DatabaseInit.getSqlSession()) {
895	                                        PluginManagerMapper mapper = session.getMapper(PluginManagerMapper.class);
896	                                        PluginManagerEntity state = mapper.selectByJarName(p.getFileName().toString());
897	                                        if (state != null) {
898	                                            if (state.getPluginVersion() != null) version = state.getPluginVersion();
899	                                            if (state.getIsDisabled() != null && state.getIsDisabled() == 1) status = "Disabled";
900	                                        }
901	                                    } catch (Exception ignored) {}
902	
903	                                    plugins.add(new PluginJarInfo(p.getFileName().toString(), version, status, sizeStr));
904	                                } catch (Exception ignored) {}
905	                            });
906	                    }
907	                }
908	                final List<PluginJarInfo> finalPlugins = plugins;
909	                Platform.runLater(() -> {
910	                    pluginTable.getItems().setAll(finalPlugins);
911	                });
912	            } catch (Exception e) {
913	                log.error("Failed to refresh plugin list", e);
914	            }
915	        }).start();
916	    }
