49	
50	    public MainWindow(Stage stage, PluginLoader loader, PluginRegistry registry) {
51	        log.debug("Initialising MainWindow");
52	        this.stage    = stage;
53	        this.loader   = loader;
54	        this.registry = registry;
55	
56	        titleBar    = new TitleBar(stage, this::openSettings);
57	        sidebar     = new Sidebar();
