18	
19	import java.util.List;
20	import java.util.function.Consumer;
21	
22	/**
23	 * Main content area.
24	 * Contains: Search bar / Tool grid / Detail panel / Page transition animations.
25	 * Bind plugin data via setPlugins(ObservableList), auto-respond to add/remove.
26	 */
27	public class ContentArea extends BorderPane {
28	
29	    // ── Sub-components ────────────────────────────────────────────
30	    private final TextField   searchField  = new TextField();
31	    private final FlowPane    toolGrid     = new FlowPane();
32	    private final DetailPanel detailPanel  = new DetailPanel();
33	    private final StackPane   pageStack    = new StackPane();
34	    private final ScrollPane  scrollPane;
35	    private final ScrollPane  pageScrollPane;
36	    private final HBox        backBar      = buildBackBar();
37	
38	    // ── State ──────────────────────────────────────────────
39	    private ObservableList<SwissKitJPlugin> plugins;
40	    private String   currentCategory = "all";
41	    private String   currentQuery    = "";
42	    private Consumer<SwissKitJPlugin> onLaunch;
43	    private Runnable onBack;
44	
45	    public ContentArea() {
46	        scrollPane     = buildScrollPane();
47	        pageScrollPane = buildPageScrollPane();
48	        buildLayout();
49	        detailPanel.setOnLaunch(p -> { if (onLaunch != null) onLaunch.accept(p); });
50	    }
51	
52	    // ── Public API ──────────────────────────────────────────
53	
54	    public void setOnLaunch(Consumer<SwissKitJPlugin> handler) { this.onLaunch = handler; }
55	    public void setOnBack(Runnable handler) { this.onBack = handler; }
56	
57	    /** Bind plugin list, auto-refresh on add/remove */
58	    public void setPlugins(ObservableList<SwissKitJPlugin> list) {
59	        this.plugins = list;
60	        list.addListener((ListChangeListener<SwissKitJPlugin>) c -> refresh());
61	        refresh();
62	    }
63	
64	    /** Switch category display */
65	    public void showCategory(String categoryId) {
66	        currentCategory = categoryId;
67	        searchField.clear();
68	        currentQuery = "";
69	        setTopMode(false, null);
70	        crossFadeTo(scrollPane);
71	        refresh();
72	        animateGridIn();
73	    }
74	
75	    /** Switch to custom page (e.g. settings, plugin market) */
76	    public void showPage(Node page, String title) {
77	        pageScrollPane.setContent(page);
78	        setTopMode(true, title);
79	        crossFadeTo(pageScrollPane);
80	        detailPanel.hide();
81	    }
82	
83	    /** Back to tool grid home */
84	    public void showToolGrid() {
85	        setTopMode(false, null);
86	        crossFadeTo(scrollPane);
87	    }
88	
89	    private void setTopMode(boolean pageMode, String title) {
90	        if (pageMode) {
91	            Label titleLabel = (Label) backBar.lookup(".back-title");
92	            if (titleLabel != null) titleLabel.setText(title != null ? title : "");
93	            backBar.setVisible(true);
94	            backBar.setManaged(true);
95	            searchField.getParent().setVisible(false);
96	            searchField.getParent().setManaged(false);
97	        } else {
98	            backBar.setVisible(false);
99	            backBar.setManaged(false);
100	            searchField.getParent().setVisible(true);
101	            searchField.getParent().setManaged(true);
102	        }
103	    }
104	
105	    // ── Layout build ──────────────────────────────────────────
106	
107	    private void buildLayout() {
108	        // Search bar
109	        HBox searchBar = buildSearchBar();
110	
111	        // Top area: back bar (hidden by default) + search bar
112	        backBar.setVisible(false);
113	        backBar.setManaged(false);
114	        VBox top = new VBox(backBar, searchBar);
115	        top.setPadding(new Insets(12, 16, 0, 16));
116	        setTop(top);
117	
118	        // Center: StackPane (switchable content) + Detail panel
119	        pageStack.getChildren().add(scrollPane);
120	        pageStack.setAlignment(Pos.TOP_LEFT);
121	
122	        HBox center = new HBox(pageStack, detailPanel);
123	        HBox.setHgrow(pageStack, Priority.ALWAYS);
124	        setCenter(center);
125	    }
126	
127	    private HBox buildBackBar() {
128	        Label backBtn = new Label("← 返回");
129	        backBtn.setStyle(
130	            "-fx-text-fill: rgba(255,255,255,0.70); -fx-font-size: 13px;" +
131	            "-fx-cursor: hand; -fx-padding: 4 10 4 0;"
132	        );
133	        backBtn.setOnMouseEntered(e ->
134	            backBtn.setStyle("-fx-text-fill: rgba(255,255,255,1); -fx-font-size: 13px;" +
135	                             "-fx-cursor: hand; -fx-padding: 4 10 4 0;")
136	        );
137	        backBtn.setOnMouseExited(e ->
138	            backBtn.setStyle("-fx-text-fill: rgba(255,255,255,0.70); -fx-font-size: 13px;" +
139	                             "-fx-cursor: hand; -fx-padding: 4 10 4 0;")
140	        );
141	        backBtn.setOnMouseClicked(e -> {
142	            showToolGrid();
143	            if (onBack != null) onBack.run();
144	        });
145	
146	        Label sep = new Label("/");
147	        sep.setStyle("-fx-text-fill: rgba(255,255,255,0.25); -fx-font-size: 13px; -fx-padding: 4 6 4 0;");
148	
149	        Label titleLabel = new Label();
150	        titleLabel.getStyleClass().add("back-title");
151	        titleLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.90); -fx-font-size: 13px; -fx-font-weight: bold;");
152	
153	        HBox bar = new HBox(6, backBtn, sep, titleLabel);
154	        bar.setAlignment(Pos.CENTER_LEFT);
155	        bar.setPrefHeight(38);
156	        return bar;
157	    }
158	
159	    private HBox buildSearchBar() {
160	        Label searchIcon = new Label("🔍");
161	        searchIcon.setStyle("-fx-font-size: 13px; -fx-text-fill: rgba(255,255,255,0.28);");
162	
163	        searchField.getStyleClass().add("search-field");
164	        searchField.setPromptText("Search tools...");
165	        searchField.setMaxWidth(Double.MAX_VALUE);
166	        HBox.setHgrow(searchField, Priority.ALWAYS);
167	        searchField.textProperty().addListener((obs, oldVal, newVal) -> {
168	            currentQuery = newVal.trim().toLowerCase();
169	            refresh();
170	        });
171	
172	        Label kbdHint = new Label("⌘K");
173	        kbdHint.setStyle(
174	            "-fx-font-size: 10px; -fx-text-fill: rgba(255,255,255,0.28);" +
175	            "-fx-background-color: rgba(255,255,255,0.06);" +
176	            "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
177	            "-fx-border-radius: 4; -fx-background-radius: 4;" +
178	            "-fx-padding: 1 5 1 5; -fx-font-family: 'SF Mono','Consolas',monospace;"
179	        );
180	
181	        HBox bar = new HBox(10, searchIcon, searchField, kbdHint);
182	        bar.getStyleClass().add("search-bar");
183	        bar.setAlignment(Pos.CENTER_LEFT);
184	        bar.setPrefHeight(38);
185	        return bar;
186	    }
187	
188	    private ScrollPane buildPageScrollPane() {
189	        ScrollPane sp = new ScrollPane();
190	        sp.getStyleClass().add("content-scroll");
191	        sp.setFitToWidth(true);
192	        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
193	        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
194	        sp.setStyle("-fx-background-color: transparent; -fx-background: transparent;");
195	        return sp;
196	    }
197	
198	    private ScrollPane buildScrollPane() {
199	        // Tool grid
200	        toolGrid.setHgap(10);
201	        toolGrid.setVgap(10);
202	        toolGrid.setPadding(new Insets(16));
203	        toolGrid.setPrefWrapLength(600);
204	
205	        VBox wrapper = new VBox(
206	            sectionHeader("FREQUENT", ""),
207	            toolGrid
208	        );
209	        wrapper.setPadding(new Insets(8, 16, 16, 16));
210	        wrapper.setSpacing(0);
211	
212	        ScrollPane sp = new ScrollPane(wrapper);
213	        sp.getStyleClass().add("content-scroll");
214	        sp.setFitToWidth(true);
215	        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
216	        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
217	        sp.setStyle("-fx-background-color: transparent; -fx-background: transparent;");
218	        return sp;
219	    }
220	
221	    // ── Grid refresh ──────────────────────────────────────────
222	
223	    private void refresh() {
224	        if (plugins == null) return;
225	
226	        List<SwissKitJPlugin> filtered = plugins.stream()
227	            .filter(this::matchesCategory)
228	            .filter(this::matchesQuery)
229	            .toList();
230	
231	        toolGrid.getChildren().clear();
232	
233	        for (int i = 0; i < filtered.size(); i++) {
234	            SwissKitJPlugin p = filtered.get(i);
235	            ToolCard card = new ToolCard(p, this::onCardSelect);
236	            card.setPrefWidth(152);
237	            card.setPrefHeight(130);
238	
239	            // Staggered entry delay
240	            int delay = i * 35;
241	            card.setOpacity(0);
242	            PauseTransition pause = new PauseTransition(Duration.millis(delay));
243	            pause.setOnFinished(e -> {
244	                FadeTransition ft = new FadeTransition(Duration.millis(240), card);
245	                ft.setFromValue(0); ft.setToValue(1);
246	                TranslateTransition tt = new TranslateTransition(Duration.millis(240), card);
247	                tt.setFromY(10); tt.setToY(0);
248	                new ParallelTransition(ft, tt).play();
249	            });
250	            pause.play();
251	
252	            toolGrid.getChildren().add(card);
253	        }
254	
255	        // Empty state message
256	        if (filtered.isEmpty()) {
257	            Label empty = new Label("No matching tools found");
258	            empty.setStyle("-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 13px;");
259	            empty.setPadding(new Insets(40, 0, 0, 0));
260	            toolGrid.getChildren().add(empty);
261	        }
262	    }
263	
264	    // ── Filter logic ──────────────────────────────────────────
265	
266	    private boolean matchesCategory(SwissKitJPlugin p) {
267	        return switch (currentCategory) {
268	            case "all"     -> true;
269	            case "plugins" -> !"builtin".equals(p.getType());
270	            case "fav"     -> false; // TODO: integrate favorites persistence
271	            default        -> p.getCategory().equalsIgnoreCase(currentCategory);
272	        };
273	    }
274	
275	    private boolean matchesQuery(SwissKitJPlugin p) {
276	        if (currentQuery.isEmpty()) return true;
277	        return p.getName().toLowerCase().contains(currentQuery)
278	            || p.getDescription().toLowerCase().contains(currentQuery);
279	    }
280	
281	    // ── Card selection ──────────────────────────────────────────
282	
283	    private void onCardSelect(SwissKitJPlugin plugin) {
284	        detailPanel.show(plugin);
285	    }
286	
287	    // ── Page transition animation (cross-fade) ──────────────────────
288	
289	    private void crossFadeTo(Node next) {
290	        Node current = pageStack.getChildren().isEmpty()
291	            ? null : pageStack.getChildren().get(0);
292	
293	        next.setOpacity(0);
294	        if (!pageStack.getChildren().contains(next))
295	            pageStack.getChildren().add(next);
296	        next.toFront();
297	
298	        FadeTransition fadeIn = new FadeTransition(Duration.millis(220), next);
299	        fadeIn.setToValue(1);
300	
301	        if (current != null && current != next) {
302	            FadeTransition fadeOut = new FadeTransition(Duration.millis(180), current);
303	            fadeOut.setToValue(0);
304	            Node finalCurrent = current;
305	            fadeOut.setOnFinished(e -> pageStack.getChildren().remove(finalCurrent));
306	            new ParallelTransition(fadeOut, fadeIn).play();
307	        } else {
308	            fadeIn.play();
309	        }
310	    }
311	
312	    private void animateGridIn() {
313	        // Grid slides in from slightly below
314	        TranslateTransition tt = new TranslateTransition(Duration.millis(280), toolGrid);
315	        tt.setFromY(12); tt.setToY(0);
316	        FadeTransition ft = new FadeTransition(Duration.millis(280), toolGrid);
317	        ft.setFromValue(0.4); ft.setToValue(1);
318	        new ParallelTransition(tt, ft).play();
319	    }
320	
321	    // ── Helper node factory ──────────────────────────────────────
322	
323	    private HBox sectionHeader(String title, String action) {
324	        Label titleLabel = new Label(title.toUpperCase());
325	        titleLabel.getStyleClass().add("section-title");
326	
327	        Region spacer = new Region();
328	        HBox.setHgrow(spacer, Priority.ALWAYS);
329	
330	        HBox row = new HBox(titleLabel, spacer);
331	        if (!action.isEmpty()) {
332	            Label actionLabel = new Label(action);
333	            actionLabel.setStyle("-fx-text-fill: #5b8cf7; -fx-font-size: 12px; -fx-cursor: hand;");
334	            row.getChildren().add(actionLabel);
335	        }
336	        row.setAlignment(Pos.CENTER_LEFT);
337	        row.setPadding(new Insets(8, 0, 10, 0));
338	        return row;
339	    }
340	}
