            items[idx].setActive(true);
            pages[idx].setVisible(true);
        });
    }

    // ── Layout: sidebar + content ────────────────────────
    HBox body = new HBox(sidebar, contentStack);
    HBox.setHgrow(contentStack, Priority.ALWAYS);

