128	    private static VBox buildGeneralTab() {
129	        Label title = sectionTitle("General Settings");
130	        Label langLabel = subLabel("Language");
131	
132	        ComboBox<String> langCombo = new ComboBox<>(FXCollections.observableArrayList("中文", "English"));
133	        langCombo.setValue(getCurrentLanguageLabel());
134	        langCombo.getStyleClass().add("glass-combo");
135	        langCombo.setMaxWidth(200);
136	        langCombo.setOnAction(e -> {
137	            String selected = langCombo.getValue();
138	            saveLanguageSetting(selected);
139	        });
140	
141	        HBox langRow = new HBox(12, langLabel, langCombo);
142	        langRow.setAlignment(Pos.CENTER_LEFT);
143	
144	        VBox root = new VBox(16, title, langRow);
145	        root.setPadding(new Insets(20));
146	        root.setStyle("-fx-background-color: transparent;");
147	        return root;
148	    }
