150	    private static String getCurrentLanguageLabel() {
151	        try (SqlSession session = DatabaseInit.getSqlSession()) {
152	            AppSettingMapper mapper = session.getMapper(AppSettingMapper.class);
153	            AppSettingEntity entity = mapper.selectByKey("language");
154	            if (entity != null && "en".equals(entity.getSettingValue())) {
155	                return "English";
156	            }
157	        } catch (Exception e) {
158	            log.debug("Could not read language setting", e);
159	        }
160	        return "中文";
161	    }
162	
163	    private static void saveLanguageSetting(String label) {
164	        new Thread(() -> {
165	            try (SqlSession session = DatabaseInit.getSqlSession()) {
166	                AppSettingMapper mapper = session.getMapper(AppSettingMapper.class);
167	                AppSettingEntity entity = mapper.selectByKey("language");
168	                if (entity != null) {
169	                    entity.setSettingValue("中文".equals(label) ? "zh" : "en");
170	                    mapper.update(entity);
171	                } else {
172	                    AppSettingEntity newEntity = new AppSettingEntity();
173	                    newEntity.setSettingKey("language");
174	                    newEntity.setSettingValue("中文".equals(label) ? "zh" : "en");
175	                    mapper.insert(newEntity);
176	                }
177	                session.commit();
178	                Platform.runLater(() -> {
179	                    Alert a = new Alert(Alert.AlertType.INFORMATION);
180	                    a.setTitle("Settings");
181	                    a.setHeaderText(null);
182	                    a.setContentText("Language changed. Restart may be required for full effect.");
183	                    a.showAndWait();
184	                });
185	            } catch (Exception e) {
186	                log.error("Failed to save language setting", e);
187	            }
188	        }).start();
189	    }
