218	    private static void loadEmailSettings(VBox root) {
219	        new Thread(() -> {
220	            try (SqlSession session = DatabaseInit.getSqlSession()) {
221	                SwissKitSettingEmailMapper mapper = session.getMapper(SwissKitSettingEmailMapper.class);
222	                SwissKitSettingEmailEntity entity = mapper.selectLatest();
223	                if (entity != null) {
224	                    Platform.runLater(() -> {
225	                        for (Node child : root.getChildren()) {
226	                            if (child instanceof HBox hb) {
227	                                Object labelNode = hb.getChildren().get(0);
228	                                if (labelNode instanceof Label lbl) {
229	                                    String text = lbl.getText();
230	                                    if (text != null) {
231	                                        Object fieldNode = hb.getChildren().get(1);
232	                                        if ("SMTP Server".equals(text) && fieldNode instanceof TextField tf) {
233	                                            tf.setText(entity.getSmtpAddress());
234	                                        } else if ("Port".equals(text) && fieldNode instanceof TextField tf2) {
235	                                            tf2.setText(String.valueOf(entity.getSmtpPort()));
236	                                        } else if ("Username".equals(text) && fieldNode instanceof TextField tf3) {
237	                                            tf3.setText(entity.getEmail());
238	                                        } else if ("Password".equals(text) && fieldNode instanceof PasswordField pf) {
239	                                            pf.setText(entity.getPassword());
240	                                        } else if ("From Address".equals(text) && fieldNode instanceof TextField tf4) {
241	                                            tf4.setText(entity.getFromAddress());
242	                                        }
243	                                    }
244	                                }
245	                            }
246	                        }
247	                        // Update TLS/SSL checkboxes
248	                        for (Node child : root.getChildren()) {
249	                            if (child instanceof VBox vb && vb.getChildren().size() == 2) {
250	                                Node inner = vb.getChildren().get(1);
251	                                if (inner instanceof HBox hb && hb.getChildren().size() == 2) {
252	                                    Object first = hb.getChildren().get(0);
253	                                    Object second = hb.getChildren().get(1);
254	                                    if (first instanceof CheckBox tlsCb && "TLS".equals(tlsCb.getText()) && entity.getNeedTLS() != null) {
255	                                        tlsCb.setSelected(entity.getNeedTLS());
256	                                    } else if (second instanceof CheckBox sslCb && "SSL".equals(sslCb.getText()) && entity.getNeedSSL() != null) {
257	                                        sslCb.setSelected(entity.getNeedSSL());
258	                                    }
259	                                }
260	                            }
261	                        }
262	                    });
263	                }
264	            } catch (Exception e) {
265	                log.debug("No existing email settings found", e);
266	            }
267	        }).start();
268	    }
269	
270	    private static VBox tlsSslRow() {
271	        CheckBox tlsCheck = new CheckBox("TLS");
272	        tlsCheck.getStyleClass().add("glass-checkbox");
273	
274	        CheckBox sslCheck = new CheckBox("SSL");
275	        sslCheck.getStyleClass().add("glass-checkbox");
276	
277	        HBox checkRow = new HBox(16, tlsCheck, sslCheck);
