288	    private static Button saveEmailBtn() {
289	        Button btn = glassBtn("Save", true);
290	        btn.setOnAction(e -> {
291	            VBox parent = (VBox) btn.getParent();
292	            saveEmailSettings(parent);
293	        });
294	        return btn;
295	    }
296	
297	    private static void saveEmailSettings(VBox form) {
298	        String smtp = null, port = null, user = null, pass = null, from = null;
299	        boolean tls = false, ssl = false;
300	        List<Node> children = form.getChildren();
301	
302	        for (Node child : children) {
303	            if (child instanceof HBox hb && hb.getChildren().size() >= 2) {
304	                Object first = hb.getChildren().get(0);
305	                if (first instanceof Label lbl) {
306	                    String text = lbl.getText();
307	                    Object field = hb.getChildren().get(1);
308	                    if ("SMTP Server".equals(text) && field instanceof TextField tf) smtp = tf.getText();
309	                    else if ("Port".equals(text) && field instanceof TextField tf) port = tf.getText();
310	                    else if ("Username".equals(text) && field instanceof TextField tf) user = tf.getText();
311	                    else if ("Password".equals(text) && field instanceof PasswordField pf) pass = pf.getText();
312	                    else if ("From Address".equals(text) && field instanceof TextField tf) from = tf.getText();
313	                }
314	            } else if (child instanceof VBox vb) {
315	                for (Node vbChild : vb.getChildren()) {
316	                    if (vbChild instanceof HBox hb && hb.getChildren().size() == 2) {
317	                        Object first = hb.getChildren().get(0);
318	                        Object second = hb.getChildren().get(1);
319	                        if (first instanceof CheckBox tlsCb && "TLS".equals(tlsCb.getText())) tls = tlsCb.isSelected();
320	                        if (second instanceof CheckBox sslCb && "SSL".equals(sslCb.getText())) ssl = sslCb.isSelected();
321	                    }
322	                }
323	            }
324	        }
325	
326	        if (smtp == null || smtp.isBlank() || port == null || port.isBlank()
327	                || user == null || user.isBlank() || pass == null || pass.isBlank()
328	                || from == null || from.isBlank()) {
329	            alert(Alert.AlertType.WARNING, "Validation Error", "All fields are required.");
330	            return;
331	        }
332	
333	        if (tls && ssl) {
334	            alert(Alert.AlertType.WARNING, "Validation Error", "TLS and SSL cannot be both selected.");
335	            return;
336	        }
337	
338	        final String fSmtp = smtp.trim();
339	        final String fPort = port.trim();
340	        final String fUser = user.trim();
341	        final String fPass = pass.trim();
342	        final String fFrom = from.trim();
343	        final boolean fTls = tls;
344	        final boolean fSsl = ssl;
