836	    private static void deployPlugin(File source) {
837	        new Thread(() -> {
838	            try {
839	                Path pluginDir = Path.of(System.getProperty("user.dir"), "plugins");
840	                Files.createDirectories(pluginDir);
841	                Path target = pluginDir.resolve(source.getName());
842	                Files.copy(source.toPath(), target, StandardCopyOption.REPLACE_EXISTING);
843	                log.info("Plugin deployed: {}", target);
844	                Platform.runLater(() -> {
845	                    pluginPathField.setText("");
846	                    refreshPluginList();
847	                    alert(Alert.AlertType.INFORMATION, "Success", "Plugin deployed: " + source.getName());
848	                });
849	            } catch (Exception ex) {
850	                log.error("Plugin deploy failed", ex);
851	                Platform.runLater(() -> alert(Alert.AlertType.ERROR, "Error", "Deploy failed: " + ex.getMessage()));
852	            }
853	        }).start();
854	    }
