856	    private static void refreshPluginList() {
857	        new Thread(() -> {
858	            try {
859	                Path pluginDir = Path.of(System.getProperty("user.dir"), "plugins");
860	                List<PluginJarInfo> plugins = new ArrayList<>();
861	                if (Files.exists(pluginDir)) {
862	                    try (var stream = Files.list(pluginDir)) {
863	                        stream.filter(p -> p.getFileName().toString().toLowerCase().endsWith(".jar"))
864	                            .forEach(p -> {
865	                                try {
866	                                    long size = Files.size(p);
867	                                    String sizeStr;
868	                                    if (size < 1024) sizeStr = size + " B";
869	                                    else if (size < 1024 * 1024) sizeStr = String.format("%.1f KB", size / 1024.0);
870	                                    else sizeStr = String.format("%.1f MB", size / (1024.0 * 1024.0));
871	
872	                                    String version = "N/A";
873	                                    String status = "Enabled";
874	
875	                                    try (SqlSession session = DatabaseInit.getSqlSession()) {
876	                                        PluginManagerMapper mapper = session.getMapper(PluginManagerMapper.class);
877	                                        PluginManagerEntity state = mapper.selectByJarName(p.getFileName().toString());
878	                                        if (state != null) {
879	                                            if (state.getPluginVersion() != null) version = state.getPluginVersion();
880	                                            if (state.getIsDisabled() != null && state.getIsDisabled() == 1) status = "Disabled";
881	                                        }
882	                                    } catch (Exception ignored) {}
883	
884	                                    plugins.add(new PluginJarInfo(p.getFileName().toString(), version, status, sizeStr));
885	                                } catch (Exception ignored) {}
886	                            });
887	                    }
888	                }
889	                final List<PluginJarInfo> finalPlugins = plugins;
890	                Platform.runLater(() -> {
891	                    pluginTable.getItems().setAll(finalPlugins);
892	                });
893	            } catch (Exception e) {
894	                log.error("Failed to refresh plugin list", e);
895	            }
896	        }).start();
897	    }
