1	package fan.summer.ui.store;
2	
3	import javafx.application.Platform;
4	import javafx.geometry.Insets;
5	import javafx.geometry.Pos;
6	import javafx.scene.control.Alert;
7	import javafx.scene.control.Button;
8	import javafx.scene.control.Label;
9	import javafx.scene.control.ProgressBar;
10	import javafx.scene.control.ScrollPane;
11	import javafx.scene.control.TextField;
12	import javafx.scene.layout.HBox;
13	import javafx.scene.layout.Priority;
14	import javafx.scene.layout.Region;
15	import javafx.scene.layout.VBox;
16	import org.slf4j.Logger;
17	import org.slf4j.LoggerFactory;
18	
19	import java.io.BufferedReader;
20	import java.io.File;
21	import java.io.FileOutputStream;
22	import java.io.InputStreamReader;
23	import java.net.HttpURLConnection;
24	import java.net.URL;
25	import java.nio.file.Files;
26	import java.nio.file.Path;
27	import java.util.ArrayList;
28	import java.util.List;
29	
30	/**
31	 * Online plugin store pane — fetches plugin list from a remote JSON API
32	 * and allows one-click installation of JAR files.
33	 */
34	public class OnlineStorePane extends VBox {
35	
36	    private static final Logger log = LoggerFactory.getLogger(OnlineStorePane.class);
37	
38	    private final Runnable onInstallComplete;
39	    private final TextField urlField;
40	    private final VBox pluginListContainer;
41	    private final ProgressBar fetchProgress;
42	    private final Label statusLabel;
43	    private final ScrollPane scrollPane;
44	    private final HBox loadingRow;
45	    private String currentStoreUrl;
46	
47	    public OnlineStorePane(Runnable onInstallComplete) {
48	        this.onInstallComplete = onInstallComplete;
49	        this.currentStoreUrl = fan.summer.ui.setting.SwissKitJSettingUi.getStoreUrl();
50	        setSpacing(20);
51	        setStyle("-fx-background-color: transparent;");
52	        setPadding(new Insets(24));
53	
54	        // Title + description
55	        Label title = new Label("Plugin Store");
56	        title.setStyle(
57	            "-fx-text-fill: rgba(255,255,255,0.90);" +
58	            "-fx-font-size: 18px; -fx-font-weight: 500;"
59	        );
60	
61	        Label desc = new Label(
62	            "Browse and install plugins from the online store. " +
63	            "Configure the store URL in Settings → Plugin Store."
64	        );
65	        desc.setStyle(
66	            "-fx-text-fill: rgba(255,255,255,0.45);" +
67	            "-fx-font-size: 12px;"
68	        );
69	        desc.setWrapText(true);
70	
71	        // Store URL input — loads from settings, editable for one-off changes
72	        urlField = new TextField();
73	        urlField.setText(currentStoreUrl);
74	        urlField.setPromptText("Enter plugin store URL...");
75	        urlField.setStyle(fieldStyle());
76	
77	        Button fetchBtn = glassBtn("Fetch", false);
78	        fetchBtn.setOnAction(e -> fetchPluginList());
79	
80	        HBox urlRow = new HBox(10, urlField, fetchBtn);
81	
82	        // Plugin list scroll area
83	        pluginListContainer = new VBox(12);
84	        pluginListContainer.setStyle("-fx-background-color: transparent;");
85	
86	        scrollPane = new ScrollPane(pluginListContainer);
87	        scrollPane.setFitToWidth(true);
88	        scrollPane.setPrefHeight(400);
89	        scrollPane.setStyle(
90	            "-fx-background-color: transparent;" +
91	            "-fx-border-color: transparent;" +
92	            "-fx-background: transparent;"
93	        );
94	
95	        // Loading row
96	        Label spinner = new Label("⏳");
97	        spinner.setStyle("-fx-font-size: 16px;");
98	        Label loadingText = new Label("Fetching plugin list...");
99	        loadingText.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px;");
100	        fetchProgress = new ProgressBar();
101	        fetchProgress.setPrefWidth(200);
102	        fetchProgress.setStyle("-fx-accent: #5b8cf7;");
103	        loadingRow = new HBox(10, spinner, loadingText, fetchProgress);
104	        loadingRow.setAlignment(Pos.CENTER_LEFT);
105	        loadingRow.setVisible(false);
106	        loadingRow.setPadding(new Insets(20));
107	
108	        // Status label
109	        statusLabel = new Label();
110	        statusLabel.setStyle(
111	            "-fx-text-fill: rgba(255,255,255,0.50);" +
112	            "-fx-font-size: 12px;"
113	        );
114	        statusLabel.setWrapText(true);
115	
116	        getChildren().addAll(title, desc, urlRow, scrollPane, loadingRow, statusLabel);
117	
118	        // Auto-fetch on creation
119	        fetchPluginList();
120	    }
121	
122	    private void fetchPluginList() {
123	        String urlStr = urlField.getText().trim();
124	        if (urlStr.isEmpty()) {
125	            showError("Please enter a store URL.");
126	            return;
127	        }
128	        currentStoreUrl = urlStr;
129	        showLoading(true);
130	        statusLabel.setText("");
131	
132	        new Thread(() -> {
133	            try {
134	                List<StorePlugin> plugins = fetchPlugins(urlStr);
135	                Platform.runLater(() -> {
136	                    showLoading(false);
137	                    displayPlugins(plugins);
138	                });
139	            } catch (Exception e) {
140	                log.error("Failed to fetch plugin list from {}", urlStr, e);
141	                Platform.runLater(() -> {
142	                    showLoading(false);
143	                    showError("Failed to fetch: " + e.getMessage());
144	                    displayEmptyState();
145	                });
146	            }
147	        }).start();
148	    }
149	
150	    private List<StorePlugin> fetchPlugins(String urlStr) throws Exception {
151	        HttpURLConnection conn = (HttpURLConnection) new URL(urlStr).openConnection();
152	        conn.setRequestMethod("GET");
153	        conn.setConnectTimeout(10000);
154	        conn.setReadTimeout(15000);
155	        conn.setRequestProperty("Accept", "application/json");
156	
157	        int responseCode = conn.getResponseCode();
158	        if (responseCode != 200) {
159	            throw new RuntimeException("HTTP " + responseCode);
160	        }
161	
162	        StringBuilder sb = new StringBuilder();
163	        try (BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()))) {
164	            String line;
165	            while ((line = br.readLine()) != null) {
166	                sb.append(line);
167	            }
168	        }
169	
170	        return parsePluginJson(sb.toString());
171	    }
172	
173	    private List<StorePlugin> parsePluginJson(String json) {
174	        List<StorePlugin> result = new ArrayList<>();
175	        // Simple JSON parser for the plugin list array
176	        // Expected format: [{ "id": "...", "name": "...", "description": "...", "version": "...", "jarUrl": "...", "iconStyle": "...", "category": "..." }, ...]
177	        try {
178	            // Find array start
179	            int arrayStart = json.indexOf('[');
180	            int arrayEnd = json.lastIndexOf(']');
181	            if (arrayStart == -1 || arrayEnd == -1) return result;
182	
183	            String arrayContent = json.substring(arrayStart + 1, arrayEnd);
184	            // Split by }{ (avoiding full regex for safety)
185	            String[] objects = arrayContent.split("\\},\\s*\\{");
186	
187	            for (String obj : objects) {
188	                if (!obj.startsWith("{")) obj = "{" + obj;
189	                if (!obj.endsWith("}")) obj = obj + "}";
190	
191	                StorePlugin p = new StorePlugin();
192	                p.id = extractJsonString(obj, "id");
193	                p.name = extractJsonString(obj, "name");
194	                p.description = extractJsonString(obj, "description");
195	                p.version = extractJsonString(obj, "version");
196	                p.jarUrl = extractJsonString(obj, "jarUrl");
197	                p.iconStyle = extractJsonString(obj, "iconStyle", "ic-blue");
198	                p.category = extractJsonString(obj, "category", "other");
199	
200	                if (p.id != null && p.name != null && p.jarUrl != null) {
201	                    result.add(p);
202	                }
203	            }
204	        } catch (Exception e) {
205	            log.warn("JSON parse error, showing partial results", e);
206	        }
207	        return result;
208	    }
209	
210	    private String extractJsonString(String json, String key) {
211	        return extractJsonString(json, key, null);
212	    }
213	
214	    private String extractJsonString(String json, String key, String defaultVal) {
215	        String search = "\"" + key + "\"";
216	        int keyPos = json.indexOf(search);
217	        if (keyPos == -1) return defaultVal;
218	
219	        int colonPos = json.indexOf(':', keyPos);
220	        if (colonPos == -1) return defaultVal;
221	
222	        int valueStart = json.indexOf('"', colonPos + 1);
223	        if (valueStart == -1) return defaultVal;
224	
225	        int valueEnd = json.indexOf('"', valueStart + 1);
226	        if (valueEnd == -1) return defaultVal;
227	
228	        return json.substring(valueStart + 1, valueEnd);
229	    }
230	
231	    private void displayPlugins(List<StorePlugin> plugins) {
232	        pluginListContainer.getChildren().clear();
233	
234	        if (plugins.isEmpty()) {
235	            displayEmptyState();
236	            return;
237	        }
238	
239	        Label countLabel = new Label(plugins.size() + " plugin(s) available");
240	        countLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px; -fx-font-weight: 500;");
241	        pluginListContainer.getChildren().add(countLabel);
242	
243	        for (StorePlugin plugin : plugins) {
244	            VBox card = buildPluginCard(plugin);
245	            pluginListContainer.getChildren().add(card);
246	        }
247	
248	        statusLabel.setText("Found " + plugins.size() + " plugin(s)");
249	        statusLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.45); -fx-font-size: 12px;");
250	    }
251	
252	    private VBox buildPluginCard(StorePlugin plugin) {
253	        VBox card = new VBox();
254	        card.setSpacing(8);
255	        card.setPadding(new Insets(16));
256	        card.setStyle(
257	            "-fx-background-color: rgba(255,255,255,0.04);" +
258	            "-fx-border-color: rgba(255,255,255,0.10);" +
259	            "-fx-border-width: 1; -fx-border-radius: 10;" +
260	            "-fx-background-radius: 10;"
261	        );
262	
263	        // Header: name + version
264	        HBox header = new HBox();
265	        Label nameLabel = new Label(plugin.name);
266	        nameLabel.setStyle(
267	            "-fx-text-fill: rgba(255,255,255,0.90);" +
268	            "-fx-font-size: 14px; -fx-font-weight: 500;"
269	        );
270	        Label versionBadge = new Label("v" + plugin.version);
271	        versionBadge.setStyle(
272	            "-fx-text-fill: rgba(255,255,255,0.40);" +
273	            "-fx-font-size: 11px; -fx-background-color: rgba(255,255,255,0.07);" +
274	            "-fx-background-radius: 4; -fx-padding: 2 6 2 6;"
275	        );
276	
277	        Label categoryBadge = new Label(plugin.category);
278	        categoryBadge.setStyle(
279	            "-fx-text-fill: rgba(255,255,255,0.35);" +
280	            "-fx-font-size: 10px; -fx-background-color: rgba(255,255,255,0.05);" +
281	            "-fx-background-radius: 4; -fx-padding: 2 6 2 6;"
282	        );
283	
284	        Region spacer = new Region();
285	        HBox.setHgrow(spacer, Priority.ALWAYS);
286	
287	        header.getChildren().addAll(nameLabel, versionBadge, categoryBadge, spacer);
288	        header.setAlignment(Pos.CENTER_LEFT);
289	
290	        // Description
291	        Label descLabel = new Label(plugin.description);
292	        descLabel.setStyle(
293	            "-fx-text-fill: rgba(255,255,255,0.50);" +
294	            "-fx-font-size: 12px;"
295	        );
296	        descLabel.setWrapText(true);
297	
298	        // ID
299	        Label idLabel = new Label(plugin.id);
300	        idLabel.setStyle(
301	            "-fx-text-fill: rgba(255,255,255,0.25);" +
302	            "-fx-font-size: 10px; -fx-font-family: 'SF Mono','Consolas',monospace;"
303	        );
304	
305	        // Action: Install button + progress
306	        ProgressBar installProgress = new ProgressBar();
307	        installProgress.setPrefWidth(Double.MAX_VALUE);
308	        installProgress.setStyle("-fx-accent: #4cd97b;");
309	        installProgress.setVisible(false);
310	
311	        Button installBtn = glassBtn("Install", true);
312	        installBtn.setOnAction(e -> installPlugin(plugin, installBtn, installProgress));
313	
314	        HBox actionRow = new HBox(10, installBtn, installProgress);
315	        actionRow.setAlignment(Pos.CENTER_LEFT);
316	
317	        card.getChildren().addAll(header, descLabel, idLabel, actionRow);
318	
319	        return card;
320	    }
321	
322	    private void installPlugin(StorePlugin plugin, Button installBtn, ProgressBar progress) {
323	        installBtn.setDisable(true);
324	        progress.setVisible(true);
325	        progress.setProgress(-1);
326	        final ProgressBar finalProgress = progress;
327	
328	        new Thread(() -> {
329	            try {
330	                Path pluginDir = Path.of(System.getProperty("user.dir"), "plugins");
331	                Files.createDirectories(pluginDir);
332	
333	                // Download JAR
334	                HttpURLConnection conn = (HttpURLConnection) new URL(plugin.jarUrl).openConnection();
335	                conn.setConnectTimeout(15000);
336	                conn.setReadTimeout(30000);
337	
338	                int responseCode = conn.getResponseCode();
339	                if (responseCode != 200) {
340	                    throw new RuntimeException("Download failed: HTTP " + responseCode);
341	                }
342	
343	                final String jarFileName;
344	                String extractedName = plugin.jarUrl.substring(plugin.jarUrl.lastIndexOf('/') + 1);
345	                if (extractedName.toLowerCase().endsWith(".jar")) {
346	                    jarFileName = extractedName;
347	                } else {
348	                    jarFileName = plugin.id.replace('.', '-') + ".jar";
349	                }
350	                Path target = pluginDir.resolve(jarFileName);
351	
352	                // Stream to file
353	                try (var in = conn.getInputStream();
354	                     var out = new FileOutputStream(target.toFile())) {
355	                    byte[] buffer = new byte[8192];
356	                    int bytesRead;
357	                    long total = 0;
358	                    long contentLength = conn.getContentLengthLong();
359	                    while ((bytesRead = in.read(buffer)) != -1) {
360	                        out.write(buffer, 0, bytesRead);
361	                        total += bytesRead;
362	                        if (contentLength > 0) {
363	                            double progressVal = (double) total / contentLength;
364	                            Platform.runLater(() -> finalProgress.setProgress(progressVal));
365	                        }
366	                    }
367	                }
368	
369	                log.info("Plugin downloaded and installed: {}", target);
370	
371	                Platform.runLater(() -> {
372	                    progress.setProgress(1.0);
373	                    statusLabel.setText("✓ Installed: " + plugin.name + " → " + jarFileName);
374	                    statusLabel.setStyle("-fx-text-fill: #4cd97b; -fx-font-size: 12px;");
375	                    installBtn.setDisable(false);
376	                    if (onInstallComplete != null) onInstallComplete.run();
377	                });
378	            } catch (Exception ex) {
379	                log.error("Plugin install failed for {}", plugin.id, ex);
380	                Platform.runLater(() -> {
381	                    progress.setVisible(false);
382	                    showError("Install failed: " + ex.getMessage());
383	                    installBtn.setDisable(false);
384	                });
385	            }
386	        }).start();
387	    }
388	
389	    private void displayEmptyState() {
390	        pluginListContainer.getChildren().clear();
391	        Label empty = new Label("No plugins available or store unreachable.");
392	        empty.setStyle(
393	            "-fx-text-fill: rgba(255,255,255,0.30);" +
394	            "-fx-font-size: 13px;"
395	        );
396	        empty.setPadding(new Insets(40));
397	        empty.setAlignment(Pos.CENTER);
398	        pluginListContainer.getChildren().add(empty);
399	    }
400	
401	    private void showLoading(boolean show) {
402	        loadingRow.setVisible(show);
403	        fetchProgress.setVisible(show);
404	    }
405	
406	    private void showError(String msg) {
407	        statusLabel.setText("❌ " + msg);
408	        statusLabel.setStyle("-fx-text-fill: #f25c5c; -fx-font-size: 12px;");
409	    }
410	
411	    private static String fieldStyle() {
412	        return "-fx-background-color: rgba(255,255,255,0.05);" +
413	               "-fx-border-color: rgba(255,255,255,0.12); -fx-border-width: 1;" +
414	               "-fx-border-radius: 8; -fx-background-radius: 8;" +
415	               "-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 13px;" +
416	               "-fx-padding: 9 12 9 12;";
417	    }
418	
419	    private static Button glassBtn(String text, boolean primary) {
420	        Button btn = new Button(text);
421	        if (primary) {
422	            btn.setStyle(
423	                "-fx-background-color: #5b8cf7; -fx-text-fill: white; -fx-font-size: 13px;" +
424	                "-fx-font-weight: 500; -fx-background-radius: 8; -fx-border-width: 0;" +
425	                "-fx-padding: 9 18 9 18; -fx-cursor: hand;"
426	            );
427	        } else {
428	            btn.setStyle(
429	                "-fx-background-color: rgba(255,255,255,0.07);" +
430	                "-fx-border-color: rgba(255,255,255,0.12); -fx-border-width: 1;" +
431	                "-fx-text-fill: rgba(255,255,255,0.75); -fx-font-size: 13px;" +
432	                "-fx-background-radius: 8; -fx-border-radius: 8;" +
433	                "-fx-padding: 9 18 9 18; -fx-cursor: hand;"
434	            );
435	        }
436	        return btn;
437	    }
438	
439	    // ── Data model ────────────────────────────────────────────────
440	
441	    public static class StorePlugin {
442	        public String id;
443	        public String name;
444	        public String description;
445	        public String version;
446	        public String jarUrl;
447	        public String iconStyle;
448	        public String category;
449	    }
450	}

